import pytest
from calculator.eval import evaluate, ParseError, DivisionByZeroError


@pytest.mark.parametrize("expr, expected", [
    ("2 + 3", 5.0),
    ("10 - 4", 6.0),
    ("3 * 7", 21.0),
    ("15 / 3", 5.0),
])
def test_basic_arithmetic(expr, expected):
    assert evaluate(expr) == expected


@pytest.mark.parametrize("expr, expected", [
    ("2 + 3 * 4", 14.0),
    ("10 - 2 * 3", 4.0),
    ("6 / 2 + 1", 4.0),
    ("2 * 3 + 4 * 5", 26.0),
])
def test_operator_precedence(expr, expected):
    assert evaluate(expr) == expected


@pytest.mark.parametrize("expr, expected", [
    ("(2 + 3) * 4", 20.0),
    ("(10 - 2) / (3 + 1)", 2.0),
    ("((2 + 3) * (4 - 1))", 15.0),
])
def test_parentheses(expr, expected):
    assert evaluate(expr) == expected


def test_single_number():
    assert evaluate("42") == 42.0


def test_decimal_number():
    assert evaluate("3.14 + 1") == 4.14


def test_division_by_zero():
    with pytest.raises(DivisionByZeroError):
        evaluate("10 / 0")


def test_missing_closing_paren():
    with pytest.raises(ParseError, match="Missing closing"):
        evaluate("(2 + 3")


def test_empty_expression():
    with pytest.raises(ParseError):
        evaluate("")
